sub extract_info {
    my ($pdf) = @_;
    my $numPages = $pdf->numPages();

    my $date = undef;
    my $author = undef;

    for my $i (1 .. $numPages) {
        my $pageText = $pdf->getPageText($i);
        if ($pageText =~ /Author:\s*(.*)/) {
            $author = $1;
        }
        if ($pageText =~ /CreationDate:\s*(\d{4}\d{2}\d{2})/) {
            $date = $1;
        }
    }

    return ($date, $author);
}

